import com.rewritetoday.sdk.Rewrite;
import com.rewritetoday.sdk.models.templates.CreateTemplateOptions;
import com.rewritetoday.sdk.models.templates.TemplateVariable;
import java.util.List;

public class Main {
  public static void main(String[] args) throws Exception {
    var rewrite = new Rewrite(System.getenv("REWRITE_API_KEY"));

    var template = rewrite.templates().create(
      CreateTemplateOptions.builder()
        .name("order_shipped")
        .content("Hi {{first_name}}, your order {{order_id}} is on the way.")
        .variables(List.of(
          TemplateVariable.builder().name("first_name").fallback("customer").build(),
          TemplateVariable.builder().name("order_id").fallback("0000").build()
        ))
        .build()
    );

    System.out.println(template);
  }
}

